// Format changes for History
const formatChanges = (beforeStr, afterStr) => {
  try {
    const before = JSON.parse(beforeStr || '{}')
    const after = JSON.parse(afterStr || '{}')
    const changes = []
    for (const key in after) {
      if (before[key] !== after[key]) {
        const keyLabel = key.replace(/_/g, ' ')
        const formatVal = (v) => (v !== null && v !== undefined && !isNaN(v) && key.includes('value') ? Number(v).toLocaleString() : v)
        changes.push(`${keyLabel}: ${formatVal(before[key]) ?? 'none'} → ${formatVal(after[key]) ?? 'none'}`)
      }
    }
    return changes.length ? changes.join(' \n ') : ''
  } catch (e) {
    return ''
  }
}

// History timeline
function HistoryTimeline({ history, open }) {
  if (!open || !history?.length) return null
  return (
    <div className="space-y-3 mt-4">
      {history.map((item, i) => (
        <div key={i} className="flex gap-3 text-sm">
          <div className="flex flex-col items-center">
            <div className="h-2 w-2 rounded-full bg-indigo-400 mt-1.5 shrink-0" />
            {i < history.length - 1 && <div className="w-px flex-1 bg-slate-200 mt-1" />}
          </div>
          <div className="pb-3 min-w-0">
            <p className="text-slate-700 font-medium">{item.change_type?.desc || item.action || 'Updated Goal'}</p>
            {item.parameters_after && (
              <p className="text-slate-500 text-xs mt-1 whitespace-pre-wrap leading-relaxed border-l-2 border-slate-200 pl-2">
                {formatChanges(item.parameters_before, item.parameters_after)}
              </p>
            )}
            <p className="text-slate-400 text-xs mt-0.5">
              {item.created_at ? format(new Date(item.created_at), 'MMM d, yyyy HH:mm') : ''}
              {(item.changed_by_employee || item.employee)?.name ? ` · ${(item.changed_by_employee || item.employee).name}` : ''}
            </p>
          </div>
        </div>
      ))}
    </div>
  )
}

// Action dialog for baseline/result update
function ActionDialog({ open, onClose, title, fields, onSubmit, loading }) {
  const [values, setValues] = useState({})
  const [displayValues, setDisplayValues] = useState({})

  useEffect(() => {
    if (open) {
      setValues({})
      setDisplayValues({})
    }
  }, [open])

  const handleChange = (key, isNumeric) => (e) => {
    const raw = e.target.value
    if (isNumeric) {
      const clean = raw.replace(/,/g, '')
      if (clean === '' || /^\d+$/.test(clean)) {
        setDisplayValues(d => ({ ...d, [key]: clean ? Number(clean).toLocaleString() : '' }))
        setValues(v => ({ ...v, [key]: clean ? parseInt(clean, 10) : '' }))
      }
    } else {
      setValues(v => ({ ...v, [key]: raw }))
      setDisplayValues(d => ({ ...d, [key]: raw }))
    }
  }

  const handleSubmit = (e) => {
    e.preventDefault()
    onSubmit(values)
  }

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle>{title}</DialogTitle>
          <DialogDescription>Fill in the required information below.</DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4 mt-2">
          {fields.map((field) => {
            const isNumeric = field.key.includes('value')
            return (
              <div key={field.key} className="space-y-2">
                <Label htmlFor={field.key}>{field.label}</Label>
                <Input
                  id={field.key}
                  type="text"
                  placeholder={field.placeholder}
                  value={isNumeric ? (displayValues[field.key] || '') : (values[field.key] || '')}
                  onChange={handleChange(field.key, isNumeric)}
                  className="h-10"
                />
              </div>
            )
          })}
          <DialogFooter className="mt-2">
            <Button type="button" variant="outline" onClick={onClose} disabled={loading}>Cancel</Button>
            <Button type="submit" className="bg-primary hover:bg-primary/95 text-white font-semibold" disabled={loading}>
              {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : 'Confirm'}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  )
}

export default function GoalDetailPage() {
  const { goal_no } = useParams()
  const router = useRouter()

  const [goal, setGoal] = useState(null)
  const [history, setHistory] = useState([])
  const [loading, setLoading] = useState(true)
  const [historyOpen, setHistoryOpen] = useState(false)
  const [actionLoading, setActionLoading] = useState(false)
  const [dialog, setDialog] = useState(null) // 'baseline' | 'result'
  const [currentUser, setCurrentUser] = useState(null)

  const fetchGoal = async () => {
    try {
      const [goalRes, histRes] = await Promise.all([
        goalsApi.get(goal_no),
        goalsApi.getHistory(goal_no),
      ])
      setGoal(goalRes.data?.goal || goalRes.data?.data || goalRes.data)
      setHistory(histRes.data?.history || histRes.data?.data || (Array.isArray(histRes.data) ? histRes.data : []))
    } catch (err) {
      console.error('Goal detail error:', err)
      toast.error('Failed to load goal details')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    setCurrentUser(getEmployee())
    fetchGoal()
  }, [goal_no])

  const handleStatusChange = async (status) => {
    setActionLoading(true)
    try {
      await goalsApi.updateStatus(goal_no, status)
      toast.success('Goal status updated')
      fetchGoal()
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to update status')
    } finally {
      setActionLoading(false)
    }
  }

  const handleDialogSubmit = async (values) => {
    setActionLoading(true)
    try {
      if (dialog === 'baseline') {
        await goalsApi.updateBaseline(goal_no, values)
        toast.success('Baseline set successfully')
      } else if (dialog === 'result') {
        await goalsApi.updateResult(goal_no, values)
        toast.success('Result updated successfully')
      }
      setDialog(null)
      fetchGoal()
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to update')
    } finally {
      setActionLoading(false)
    }
  }

  // Progress calculation for By Value
  const getValueProgress = () => {
    if (!goal) return 0
    const start = parseFloat(goal.start_value) || 0
    const target = parseFloat(goal.target_value) || 100
    const achieved = parseFloat(goal.achieved_value) || 0
    if (target === start) return 0
    return Math.min(100, Math.max(0, ((achieved - start) / (target - start)) * 100))
  }

  const getBaselineFields = () => {
    const gt = goal?.goal_type
    if (gt === 1) return [
      { key: 'start_value', label: 'Start Value', placeholder: '0' },
      { key: 'target_value', label: 'Target Value', placeholder: '100' },
    ]
    if (gt === 2) return [
      { key: 'start_date', label: 'Start Date', type: 'date' },
      { key: 'target_date', label: 'Target Date', type: 'date' },
    ]
    if (gt === 3) return [
      { key: 'start_state', label: 'Start State', placeholder: 'e.g. Pending' },
      { key: 'target_state', label: 'Target State', placeholder: 'e.g. Completed' },
    ]
    return []
  }

  const getResultFields = () => {
    const gt = goal?.goal_type
    if (gt === 1) return [{ key: 'achieved_value', label: 'Achieved Value', placeholder: '0' }]
    if (gt === 2) return [{ key: 'achieved_date', label: 'Achieved Date', type: 'date' }]
    if (gt === 3) return [{ key: 'achieved_state', label: 'Achieved State', placeholder: 'e.g. Completed' }]
    return []
  }

  if (loading) {
    return (
      <div className="max-w-3xl mx-auto space-y-5">
        <Skeleton className="h-6 w-32" />
        <Card className="border-slate-200">
          <CardContent className="p-6 space-y-4">
            <Skeleton className="h-8 w-72" />
            <Skeleton className="h-4 w-full" />
            <Skeleton className="h-4 w-3/4" />
            <div className="flex gap-3 mt-4">
              <Skeleton className="h-8 w-24 rounded-full" />
              <Skeleton className="h-8 w-24 rounded-full" />
            </div>
          </CardContent>
        </Card>
      </div>
    )
  }

  if (!goal) {
    return (
      <div className="max-w-3xl mx-auto text-center py-20">
        <p className="text-slate-500">Goal not found.</p>
        <Link href="/goals"><Button className="mt-4">Back to Goals</Button></Link>
      </div>
    )
  }

  const status = goal.status

  const formatNumber = (val) => {
    if (val === null || val === undefined) return '—'
    return Number(val).toLocaleString()
  }

  const isReadOnly = goal && currentUser && parseInt(goal.created_by) === parseInt(currentUser.employee_no) && parseInt(goal.employee_no) !== parseInt(currentUser.employee_no)

  return (
    <div className="max-w-3xl mx-auto space-y-5">
      {/* Back */}
      <Link href="/goals" className="inline-flex items-center gap-1.5 text-sm text-slate-500 hover:text-primary transition-colors">
        <ArrowLeft className="h-4 w-4" /> Back to Goals
      </Link>

      {/* Goal info card */}
      <Card className="border border-slate-200 border-t-[3px] border-t-primary shadow-sm rounded-none bg-white">
        <CardContent className="p-6">
          <div className="flex items-start justify-between gap-4 flex-wrap">
            <div className="flex items-start gap-4 flex-1 min-w-0">
              <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-xl bg-slate-100 border border-slate-200 text-slate-600">
                <Target className="h-6 w-6 text-primary" />
              </div>
              <div className="flex-1 min-w-0">
                <h2 className="text-xl font-bold text-slate-900 leading-tight">{goal.goal_name}</h2>
                <p className="text-sm text-slate-500 mt-0.5">{goal.cycle?.cycle_name}</p>
                <div className="flex flex-wrap gap-2 mt-3">
                  <GoalTypeBadge type={goal.goal_type} />
                  <GoalStatusBadge status={goal.status} />
                </div>
              </div>
            </div>
          </div>

          {/* Details grid */}
          <div className="mt-5 grid grid-cols-2 sm:grid-cols-3 gap-4">
            <div>
              <p className="text-xs text-slate-400 uppercase tracking-wide font-medium">Weight</p>
              <p className="mt-1 font-semibold text-slate-800">{goal.weight}</p>
            </div>
            {goal.deadline && (
              <div>
                <p className="text-xs text-slate-400 uppercase tracking-wide font-medium">Deadline</p>
                <p className="mt-1 font-semibold text-slate-800 flex items-center gap-1">
                  <Calendar className="h-3.5 w-3.5 text-slate-400" />
                  {format(new Date(goal.deadline), 'MMM d, yyyy')}
                </p>
              </div>
            )}
          </div>

          {goal.description && (
            <>
              <Separator className="my-4" />
              <div>
                <p className="text-xs text-slate-400 uppercase tracking-wide font-medium mb-1.5">Description</p>
                <p className="text-sm text-slate-600 leading-relaxed">{goal.description}</p>
              </div>
            </>
          )}

          {goal.how_to_measure && (
            <div className="mt-3">
              <p className="text-xs text-slate-400 uppercase tracking-wide font-medium mb-1.5">How to Measure</p>
              <p className="text-sm text-slate-600 leading-relaxed">{goal.how_to_measure}</p>
            </div>
          )}
        </CardContent>
      </Card>

      {/* Progress section */}
      {status >= 2 && (
        <Card className="border border-slate-200 border-t-[3px] border-t-primary shadow-sm rounded-none bg-white">
          <CardHeader className="pb-3 border-b border-slate-100">
            <CardTitle className="text-base font-semibold flex items-center gap-2">
              <BarChart3 className="h-4 w-4 text-primary" /> Progress
            </CardTitle>
          </CardHeader>
          <CardContent className="pt-4 space-y-4">
            {goal.goal_type === 1 && (
              <div className="space-y-2">
                <div className="flex justify-between text-sm">
                  <span className="text-slate-500">Start: {formatNumber(goal.start_value)}</span>
                  <span className="text-slate-800 font-semibold">
                    Achieved: {formatNumber(goal.achieved_value)} / {formatNumber(goal.target_value)}
                  </span>
                </div>
                <Progress value={getValueProgress()} className="h-3 bg-slate-100" />
                <p className="text-xs text-slate-400 text-right">{getValueProgress().toFixed(1)}%</p>
              </div>
            )}
            {goal.goal_type === 2 && (
              <div className="grid grid-cols-3 gap-4 text-sm text-center">
                <div className="rounded-lg bg-slate-50 p-3">
                  <p className="text-xs text-slate-400 mb-1">Start Date</p>
                  <p className="font-semibold text-slate-700">{goal.start_date ? format(new Date(goal.start_date), 'MMM d, yyyy') : '—'}</p>
                </div>
                <div className="rounded-lg bg-green-50 p-3">
                  <p className="text-xs text-slate-400 mb-1">Achieved</p>
                  <p className="font-semibold text-green-700">{goal.achieved_date ? format(new Date(goal.achieved_date), 'MMM d, yyyy') : '—'}</p>
                </div>
                <div className="rounded-lg bg-indigo-50/50 p-3">
                  <p className="text-xs text-slate-400 mb-1">Target Date</p>
                  <p className="font-semibold text-primary">{goal.target_date ? format(new Date(goal.target_date), 'MMM d, yyyy') : '—'}</p>
                </div>
              </div>
            )}
            {goal.goal_type === 3 && (
              <div className="grid grid-cols-3 gap-4 text-sm text-center">
                <div className="rounded-lg bg-slate-50 p-3">
                  <p className="text-xs text-slate-400 mb-1">Start State</p>
                  <p className="font-semibold text-slate-700">{goal.start_state || '—'}</p>
                </div>
                <div className="rounded-lg bg-green-50 p-3">
                  <p className="text-xs text-slate-400 mb-1">Achieved</p>
                  <p className="font-semibold text-green-700">{goal.achieved_state || '—'}</p>
                </div>
                <div className="rounded-lg bg-indigo-50/50 p-3">
                  <p className="text-xs text-slate-400 mb-1">Target State</p>
                  <p className="font-semibold text-primary">{goal.target_state || '—'}</p>
                </div>
              </div>
            )}
          </CardContent>
        </Card>
      )}

      {/* Action buttons */}
      {!isReadOnly && (
        <Card className="border border-slate-200 shadow-sm rounded-none bg-white">
          <CardContent className="p-4">
            <div className="flex flex-wrap gap-2">
              {status === 1 && (
                <>
                  <Button
                    onClick={() => setDialog('baseline')}
                    className="bg-primary hover:bg-primary/95 text-white font-semibold"
                    disabled={actionLoading}
                  >
                    Set Baseline
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => handleStatusChange(5)}
                    disabled={actionLoading}
                    className="border-amber-300 text-amber-700 hover:bg-amber-50"
                  >
                    <Archive className="mr-2 h-4 w-4" /> Archive
                  </Button>
                </>
              )}
              {status === 2 && (
                <>
                  <Button
                    onClick={() => setDialog('result')}
                    className="bg-primary hover:bg-primary/95 text-white font-semibold"
                    disabled={actionLoading}
                  >
                    Update Result
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => handleStatusChange(3)}
                    disabled={actionLoading}
                    className="border-green-300 text-green-700 hover:bg-green-50"
                  >
                    <CheckCircle2 className="mr-2 h-4 w-4" /> Mark Successful
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => handleStatusChange(4)}
                    disabled={actionLoading}
                    className="border-red-300 text-red-700 hover:bg-red-50"
                  >
                    <XCircle className="mr-2 h-4 w-4" /> Mark Failed
                  </Button>
                  <Button
                    variant="outline"
                    onClick={() => handleStatusChange(5)}
                    disabled={actionLoading}
                    className="border-amber-300 text-amber-700 hover:bg-amber-50"
                  >
                    <Archive className="mr-2 h-4 w-4" /> Archive
                  </Button>
                </>
              )}
              {actionLoading && <Loader2 className="h-5 w-5 animate-spin text-primary self-center" />}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Reviewers */}
      <ReviewerSection goalNo={goal_no} readOnly={isReadOnly} />

      {/* Comments */}
      <CommentThread goalNo={goal_no} readOnly={isReadOnly} />

      {/* History */}
      <Card className="border border-slate-200 shadow-sm rounded-none bg-white">
        <CardContent className="p-4">
          <button
            type="button"
            onClick={() => setHistoryOpen((v) => !v)}
            className="flex w-full items-center justify-between text-sm font-semibold text-slate-700 hover:text-primary transition-colors cursor-pointer"
          >
            <span className="flex items-center gap-2">
              <Clock className="h-4 w-4 text-slate-400" /> Change History
              <span className="text-xs font-normal text-slate-400">({history.length})</span>
            </span>
            {historyOpen ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
          </button>
          <HistoryTimeline history={history} open={historyOpen} />
        </CardContent>
      </Card>

      {/* Action dialogs */}
      <ActionDialog
        open={dialog === 'baseline'}
        onClose={() => setDialog(null)}
        title="Set Baseline"
        fields={getBaselineFields()}
        onSubmit={handleDialogSubmit}
        loading={actionLoading}
      />
      <ActionDialog
        open={dialog === 'result'}
        onClose={() => setDialog(null)}
        title="Update Result"
        fields={getResultFields()}
        onSubmit={handleDialogSubmit}
        loading={actionLoading}
      />
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { useRouter } from 'next/navigation'
import { goalsApi, cyclesApi, employeesApi } from '@/lib/api'
import { getEmployee } from '@/lib/auth'
import { toast } from 'sonner'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Loader2, Target, Hash } from 'lucide-react'
import Link from 'next/link'
import { ArrowLeft } from 'lucide-react'

const GOAL_TYPES = [
  { value: '1', label: 'By Value', description: 'Track progress by numeric values' },
  { value: '2', label: 'By Date', description: 'Track progress by date milestones' },
  { value: '3', label: 'By State', description: 'Track progress by state/status changes' },
]

export default function NewGoalPage() {
  const router = useRouter()
  const [cycles, setCycles] = useState([])
  const [loadingCycles, setLoadingCycles] = useState(true)
  const [submitting, setSubmitting] = useState(false)
  const [employees, setEmployees] = useState([])
  const [currentUser, setCurrentUser] = useState(null)

  const [startValueInput, setStartValueInput] = useState('')
  const [targetValueInput, setTargetValueInput] = useState('')

  const [form, setForm] = useState({
    cycle_no: '',
    employee_no: '',
    goal_name: '',
    description: '',
    how_to_measure: '',
    weight: '',
    deadline: '',
    goal_type: '',
    primary_reviewer: '',
    secondary_reviewer: '',
    // By Value
    target_value: '',
    start_value: '',
    // By Date
    target_date: '',
    start_date: '',
    // By State
    target_state: '',
    start_state: '',
  })

  useEffect(() => {
    const user = getEmployee()
    setCurrentUser(user)
    fetchEmployees()
    fetchCycles()
  }, [])

  const fetchEmployees = async () => {
    try {
      const res = await employeesApi.list()
      const data = res.data?.employees || res.data?.data || (Array.isArray(res.data) ? res.data : [])
      setEmployees(data)
    } catch (err) {
      console.error('Employees fetch error:', err)
    }
  }

  const fetchCycles = async () => {
    try {
      const res = await cyclesApi.list({ status: 1 })
      const data = res.data?.cycles || res.data?.data || (Array.isArray(res.data) ? res.data : [])
      setCycles(data)
    } catch (err) {
      console.error('Cycles error:', err)
      toast.error('Failed to load cycles')
    } finally {
      setLoadingCycles(false)
    }
  }

  const set = (key) => (e) => setForm((f) => ({ ...f, [key]: e.target?.value ?? e }))

  const handleSubmit = async (e) => {
    e.preventDefault()

    if (!form.cycle_no || !form.goal_name || !form.weight || !form.goal_type) {
      toast.error('Please fill in all required fields.')
      return
    }

    const payload = {
      cycle_no: parseInt(form.cycle_no),
      goal_name: form.goal_name,
      description: form.description,
      how_to_measure: form.how_to_measure,
      weight: parseInt(form.weight, 10),
      deadline: form.deadline || null,
      goal_type: parseInt(form.goal_type),
    }

    if (form.employee_no && form.employee_no !== 'myself') {
      payload.employee_no = parseInt(form.employee_no)
    }

    const gt = parseInt(form.goal_type)
    if (gt === 1) {
      payload.target_value = parseInt(form.target_value, 10) || 0
      payload.start_value = parseInt(form.start_value, 10) || 0
    } else if (gt === 2) {
      payload.target_date = form.target_date
      payload.start_date = form.start_date
    } else if (gt === 3) {
      payload.target_state = form.target_state
      payload.start_state = form.start_state
    }

    setSubmitting(true)
    try {
      const res = await goalsApi.create(payload)
      const goal = res.data?.goal || res.data?.data || res.data

      // Chain reviewer creations
      if (form.primary_reviewer) {
        try {
          await goalsApi.addReviewer(goal.goal_no, {
            reviewer: parseInt(form.primary_reviewer, 10),
            reviewer_type: 1
          })
        } catch (rErr) {
          console.error("Failed to add primary reviewer:", rErr)
        }
      }

      if (form.secondary_reviewer) {
        try {
          await goalsApi.addReviewer(goal.goal_no, {
            reviewer: parseInt(form.secondary_reviewer, 10),
            reviewer_type: 2
          })
        } catch (rErr) {
          console.error("Failed to add secondary reviewer:", rErr)
        }
      }

      toast.success('Goal created successfully!')
      router.push(`/goals/${goal.goal_no}`)
    } catch (err) {
      const msg = err?.response?.data?.message || 'Failed to create goal.'
      toast.error(msg)
    } finally {
      setSubmitting(false)
    }
  }

  return (
    <div className="max-w-2xl mx-auto space-y-5">
      {/* Back link */}
      <Link href="/goals" className="inline-flex items-center gap-1.5 text-sm text-slate-500 hover:text-primary transition-colors">
        <ArrowLeft className="h-4 w-4" />
        Back to Goals
      </Link>

      <div>
        <h2 className="text-xl font-bold text-slate-900">Create New Goal</h2>
        <p className="text-xs text-slate-500 mt-0.5">Define a measurable performance goal</p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-5">
        {/* Basic info */}
        <Card className="border-slate-200 shadow-sm rounded-md">
          <CardHeader className="pb-4">
            <CardTitle className="text-base font-semibold flex items-center gap-2">
              <Target className="h-4 w-4 text-primary" />
              Goal Details
            </CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            {/* Cycle */}
            <div className="space-y-2">
              <Label>Cycle <span className="text-red-500">*</span></Label>
              <Select value={form.cycle_no} onValueChange={set('cycle_no')} disabled={loadingCycles}>
                <SelectTrigger className="bg-slate-50 border-slate-200">
                  <SelectValue placeholder={loadingCycles ? 'Loading...' : 'Select a cycle'} />
                </SelectTrigger>
                <SelectContent>
                  {cycles.map((c) => (
                    <SelectItem key={c.cycle_no} value={String(c.cycle_no)}>
                      {c.cycle_name}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {(currentUser?.role === 'supervisor' || currentUser?.role === 'hr_admin') && (
              <div className="space-y-2">
                <Label>Assign To</Label>
                <Select value={form.employee_no} onValueChange={set('employee_no')}>
                  <SelectTrigger className="bg-slate-50 border-slate-200">
                    <SelectValue placeholder="Myself (Default)" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="myself">Myself (Default)</SelectItem>
                    {employees.map((e) => (
                      <SelectItem key={e.employee_no} value={String(e.employee_no)}>
                        {e.employee_name || e.name}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            )}

            {/* Goal name */}
            <div className="space-y-2">
              <Label htmlFor="goal_name">
                Goal Name <span className="text-red-500">*</span>
              </Label>
              <Input
                id="goal_name"
                placeholder="e.g. Increase customer satisfaction score"
                value={form.goal_name}
                onChange={set('goal_name')}
                className="h-10"
              />
            </div>

            {/* Description */}
            <div className="space-y-2">
              <Label htmlFor="description">Description</Label>
              <Textarea
                id="description"
                placeholder="Describe this goal in detail…"
                value={form.description}
                onChange={set('description')}
                rows={3}
                className="resize-none"
              />
            </div>

            {/* How to measure */}
            <div className="space-y-2">
              <Label htmlFor="how_to_measure">How to Measure</Label>
              <Textarea
                id="how_to_measure"
                placeholder="Describe how progress will be measured…"
                value={form.how_to_measure}
                onChange={set('how_to_measure')}
                rows={2}
                className="resize-none"
              />
            </div>

            {/* Weight + Deadline */}
            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <Label htmlFor="weight">
                  Weight <span className="text-red-500">*</span>
                </Label>
                <Input
                  id="weight"
                  type="number"
                  min="1"
                  placeholder="e.g. 30"
                  value={form.weight}
                  onChange={set('weight')}
                  className="h-10"
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="deadline">Deadline</Label>
                <Input
                  id="deadline"
                  type="date"
                  value={form.deadline}
                  onChange={set('deadline')}
                  className="h-10"
                />
              </div>
            </div>

            {/* Reviewer Assignment directly inside creation */}
            <div className="grid grid-cols-2 gap-4 border-t border-slate-100 pt-4">
              <div className="space-y-2">
                <Label>Primary Reviewer</Label>
                <Select
                  value={form.primary_reviewer}
                  onValueChange={(val) => setForm(f => ({ ...f, primary_reviewer: val }))}
                >
                  <SelectTrigger className="bg-slate-50 border-slate-200">
                    <SelectValue placeholder="Select primary reviewer" />
                  </SelectTrigger>
                  <SelectContent>
                    {employees
                      .filter(e => e.employee_no !== currentUser?.employee_no && String(e.employee_no) !== form.secondary_reviewer)
                      .map((e) => (
                        <SelectItem key={e.employee_no} value={String(e.employee_no)}>
                          {e.employee_name || e.name}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label>Secondary Reviewer</Label>
                <Select
                  value={form.secondary_reviewer}
                  onValueChange={(val) => setForm(f => ({ ...f, secondary_reviewer: val }))}
                >
                  <SelectTrigger className="bg-slate-50 border-slate-200">
                    <SelectValue placeholder="Select secondary reviewer" />
                  </SelectTrigger>
                  <SelectContent>
                    {employees
                      .filter(e => e.employee_no !== currentUser?.employee_no && String(e.employee_no) !== form.primary_reviewer)
                      .map((e) => (
                        <SelectItem key={e.employee_no} value={String(e.employee_no)}>
                          {e.employee_name || e.name}
                        </SelectItem>
                      ))}
                  </SelectContent>
                </Select>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Goal Type */}
        <Card className="border-slate-200 shadow-sm rounded-md">
          <CardHeader className="pb-4">
            <CardTitle className="text-base font-semibold flex items-center gap-2">
              <Hash className="h-4 w-4 text-primary" />
              Goal Type &amp; Targets
            </CardTitle>
            <CardDescription>Choose how this goal will be tracked</CardDescription>
          </CardHeader>
          <CardContent className="space-y-4">
            {/* Goal type radio cards */}
            <div className="grid grid-cols-3 gap-3">
              {GOAL_TYPES.map((type) => (
                <button
                  key={type.value}
                  type="button"
                  onClick={() => setForm((f) => ({ ...f, goal_type: type.value }))}
                  className={`rounded-xl border-2 p-3 text-left transition-all ${
                    form.goal_type === type.value
                      ? 'border-primary bg-indigo-50/30'
                      : 'border-slate-200 hover:border-primary/50 hover:bg-slate-50'
                  }`}
                >
                  <p className={`font-semibold text-sm ${form.goal_type === type.value ? 'text-primary' : 'text-slate-700'}`}>
                    {type.label}
                  </p>
                  <p className="text-[10px] text-slate-400 mt-0.5 leading-snug">{type.description}</p>
                </button>
              ))}
            </div>

            {/* Conditional fields */}
            {form.goal_type === '1' && (
              <div className="grid grid-cols-2 gap-4 pt-2">
                <div className="space-y-2">
                  <Label>Start Value</Label>
                  <Input
                    placeholder="0"
                    value={startValueInput}
                    onChange={(e) => {
                      const raw = e.target.value.replace(/,/g, '');
                      if (raw === '' || /^\d+$/.test(raw)) {
                        setStartValueInput(raw ? Number(raw).toLocaleString() : '');
                        setForm(f => ({ ...f, start_value: raw }));
                      }
                    }}
                    className="h-10"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Target Value</Label>
                  <Input
                    placeholder="100"
                    value={targetValueInput}
                    onChange={(e) => {
                      const raw = e.target.value.replace(/,/g, '');
                      if (raw === '' || /^\d+$/.test(raw)) {
                        setTargetValueInput(raw ? Number(raw).toLocaleString() : '');
                        setForm(f => ({ ...f, target_value: raw }));
                      }
                    }}
                    className="h-10"
                  />
                </div>
              </div>
            )}

            {form.goal_type === '2' && (
              <div className="grid grid-cols-2 gap-4 pt-2">
                <div className="space-y-2">
                  <Label>Start Date</Label>
                  <Input type="date" value={form.start_date} onChange={set('start_date')} className="h-10" />
                </div>
                <div className="space-y-2">
                  <Label>Target Date</Label>
                  <Input type="date" value={form.target_date} onChange={set('target_date')} className="h-10" />
                </div>
              </div>
            )}

            {form.goal_type === '3' && (
              <div className="grid grid-cols-2 gap-4 pt-2">
                <div className="space-y-2">
                  <Label>Start State</Label>
                  <Input placeholder="e.g. Pending" value={form.start_state} onChange={set('start_state')} className="h-10" />
                </div>
                <div className="space-y-2">
                  <Label>Target State</Label>
                  <Input placeholder="e.g. Completed" value={form.target_state} onChange={set('target_state')} className="h-10" />
                </div>
              </div>
            )}
          </CardContent>
        </Card>

        {/* Actions */}
        <div className="flex items-center gap-3 justify-end">
          <Link href="/goals">
            <Button type="button" variant="outline" disabled={submitting}>
              Cancel
            </Button>
          </Link>
          <Button
            type="submit"
            className="bg-primary hover:bg-primary/95 text-white px-6 font-semibold"
            disabled={submitting}
          >
            {submitting ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Creating…
              </>
            ) : (
              'Create Goal'
            )}
          </Button>
        </div>
      </form>
    </div>
  )
}

'use client'

import { useEffect, useState, Suspense } from 'react'
import Link from 'next/link'
import { useSearchParams } from 'next/navigation'
import { goalsApi } from '@/lib/api'
import { GoalStatusBadge } from '@/components/praise/GoalStatusBadge'
import { GoalTypeBadge } from '@/components/praise/GoalTypeBadge'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Card, CardContent } from '@/components/ui/card'
import { Skeleton } from '@/components/ui/skeleton'
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Plus, Search, Target, Calendar, Weight, ChevronRight } from 'lucide-react'
import { format } from 'date-fns'

const STATUS_TABS = [
  { key: 'all', label: 'All', value: null },
  { key: 'created', label: 'Created', value: 1 },
  { key: 'baselined', label: 'Baselined', value: 2 },
  { key: 'successful', label: 'Successful', value: 3 },
  { key: 'failed', label: 'Failed', value: 4 },
  { key: 'archived', label: 'Archived', value: 5 },
]

function GoalsContent() {
  const searchParams = useSearchParams()
  const isCreatedView = searchParams?.get('created') === 'true'

  const [goals, setGoals] = useState([])
  const [filtered, setFiltered] = useState([])
  const [loading, setLoading] = useState(true)
  const [search, setSearch] = useState('')
  const [activeTab, setActiveTab] = useState('all')

  const fetchGoals = async () => {
    setLoading(true)
    try {
      const res = await goalsApi.list(isCreatedView ? { created_by_me: true } : {})
      const data = res.data?.goals || res.data?.data || (Array.isArray(res.data) ? res.data : [])
      setGoals(data)
      setFiltered(data)
    } catch (err) {
      console.error('Goals error:', err)
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchGoals()
  }, [isCreatedView])

  useEffect(() => {
    let result = goals

    const tab = STATUS_TABS.find((t) => t.key === activeTab)
    if (tab?.value !== null && tab?.value !== undefined) {
      result = result.filter((g) => g.status === tab.value)
    }

    if (search.trim()) {
      const q = search.toLowerCase()
      result = result.filter((g) => g.goal_name?.toLowerCase().includes(q))
    }

    setFiltered(result)
  }, [goals, activeTab, search])

  return (
    <div className="space-y-5">
      {/* Header */}
      <div className="flex items-center justify-between gap-4">
        <div>
          <h2 className="text-xl font-bold text-slate-900">
            {isCreatedView ? 'Created Goals' : 'My Goals'}
          </h2>
          <p className="text-xs text-slate-500 mt-0.5">
            {isCreatedView ? 'Goals created by you for yourself or other team members' : 'Track and manage your performance goals'}
          </p>
        </div>
        <Link href="/goals/new">
          <Button className="bg-primary hover:bg-primary/95 text-white shadow-sm h-9 text-xs font-semibold">
            <Plus className="mr-1.5 h-3.5 w-3.5" />
            New Goal
          </Button>
        </Link>
      </div>

      {/* Filters */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1 max-w-sm">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
          <Input
            placeholder="Search goals…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="pl-9 h-10"
          />
        </div>
      </div>

      {/* Status tabs */}
      <Tabs value={activeTab} onValueChange={setActiveTab}>
        <TabsList className="bg-slate-100 h-9">
          {STATUS_TABS.map((tab) => (
            <TabsTrigger key={tab.key} value={tab.key} className="text-xs h-7">
              {tab.label}
            </TabsTrigger>
          ))}
        </TabsList>
      </Tabs>

      {/* Goals list */}
      {loading ? (
        <div className="space-y-3">
          {[...Array(4)].map((_, i) => (
            <Card key={i} className="border-slate-200">
              <CardContent className="p-5">
                <div className="flex items-start gap-4">
                  <Skeleton className="h-12 w-12 rounded-xl" />
                  <div className="flex-1 space-y-2">
                    <Skeleton className="h-5 w-60" />
                    <Skeleton className="h-4 w-40" />
                    <div className="flex gap-2 mt-2">
                      <Skeleton className="h-6 w-20 rounded-full" />
                      <Skeleton className="h-6 w-24 rounded-full" />
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <Card className="border-slate-200 border-dashed">
          <CardContent className="flex flex-col items-center justify-center py-16 text-center">
            <div className="flex h-16 w-16 items-center justify-center rounded-full bg-slate-50 border border-slate-100 mb-4">
              <Target className="h-8 w-8 text-slate-400" />
            </div>
            <p className="font-semibold text-slate-700 text-sm">
              {search ? 'No goals match your search' : 'No goals yet'}
            </p>
            <p className="mt-1 text-xs text-slate-400 max-w-xs">
              {search ? 'Try a different search term or filter.' : 'Create your first goal to start tracking performance.'}
            </p>
            {!search && (
              <Link href="/goals/new" className="mt-5">
                <Button className="bg-primary hover:bg-primary/95 text-white h-8 text-xs font-semibold">
                  <Plus className="mr-1.5 h-3 w-3" /> Create Goal
                </Button>
              </Link>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-3">
          {filtered.map((goal) => (
            <Link key={goal.goal_no} href={`/goals/${goal.goal_no}`}>
              <Card className="border-slate-200 shadow-sm hover:shadow-md hover:border-primary/20 transition-all cursor-pointer group">
                <CardContent className="p-5">
                  <div className="flex items-start gap-4">
                    <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-xl bg-slate-100 border border-slate-200/60 group-hover:bg-slate-200 transition-colors">
                      <Target className="h-6 w-6 text-primary" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2">
                        <p className="font-semibold text-slate-800 leading-snug group-hover:text-primary transition-colors text-sm">
                          {goal.goal_name}
                        </p>
                        <ChevronRight className="h-4 w-4 text-slate-300 group-hover:text-primary/75 shrink-0 mt-0.5 transition-colors" />
                      </div>
                      <p className="text-xs text-slate-400 mt-1">
                        {goal.cycle?.cycle_name || 'No cycle'}
                      </p>
                      <div className="flex flex-wrap items-center gap-2 mt-3">
                        <GoalTypeBadge type={goal.goal_type} />
                        <GoalStatusBadge status={goal.status} />
                        <span className="flex items-center gap-1 text-xs text-slate-500">
                          <Weight className="h-3 w-3" />
                          Weight: {goal.weight}
                        </span>
                        {goal.deadline && (
                          <span className="flex items-center gap-1 text-xs text-slate-500">
                            <Calendar className="h-3 w-3" />
                            {format(new Date(goal.deadline), 'MMM d, yyyy')}
                          </span>
                        )}
                      </div>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </Link>
          ))}
        </div>
      )}
    </div>
  )
}

export default function GoalsPage() {
  return (
    <Suspense fallback={<div className="p-8 text-center text-slate-500">Loading goals...</div>}>
      <GoalsContent />
    </Suspense>
  )
}

