'use client'

import { Menu } from 'lucide-react'
import { getEmployee, clearAuth, authApi } from '@/lib/auth'
import { useEffect, useState, Suspense } from 'react'
import { useRouter, usePathname, useSearchParams } from 'next/navigation'
import { toast } from 'sonner'
import Link from 'next/link'

function TopBarContent({ onMenuClick }) {
  const router = useRouter()
  const pathname = usePathname()
  const searchParams = useSearchParams()
  const [employee, setEmployee] = useState(null)

  useEffect(() => {
    setEmployee(getEmployee())
  }, [])

  const handleLogout = async () => {
    try {
      await authApi.logout()
    } catch {}
    clearAuth()
    router.replace('/login')
    toast.success('Logged out successfully')
  }

  const isCreated = searchParams?.get('created') === 'true'

  // Generate breadcrumb path array
  const getBreadcrumbs = () => {
    const parts = pathname.split('/').filter(Boolean)
    const crumbs = [{ label: 'Home', href: '/dashboard' }]

    if (parts.length === 0) return crumbs

    let currentPath = ''
    parts.forEach((part) => {
      currentPath += `/${part}`
      let label = part.charAt(0).toUpperCase() + part.slice(1)

      if (part === 'dashboard') {
        return // skip dashboard as Home represents it
      }

      if (part === 'goals') {
        label = isCreated ? 'Created Goals' : 'My Goals'
      } else if (part === 'new') {
        label = 'New Goal'
      } else if (!isNaN(part)) {
        label = 'Goal Details'
      } else if (part === 'team') {
        label = 'Team'
      } else if (part === 'admin') {
        label = 'Admin'
      } else if (part === 'employees') {
        label = 'Employees'
      } else if (part === 'cycles') {
        label = 'Cycles'
      } else if (part === 'clients') {
        label = 'Clients'
      }

      crumbs.push({ label, href: currentPath })
    })

    return crumbs
  }

  const crumbs = getBreadcrumbs()

  return (
    <header className="flex h-14 shrink-0 items-center justify-between border-b border-[#dee2e6] bg-white px-4 lg:px-6 shadow-sm">
      <div className="flex items-center gap-4">
        {/* Toggle Sidebar Button */}
        <button
          onClick={onMenuClick}
          className="rounded p-1.5 text-slate-600 hover:text-slate-900 hover:bg-slate-50 transition-colors"
          aria-label="Toggle Sidebar"
        >
          <Menu className="h-5 w-5" />
        </button>

        {/* AdminLTE style breadcrumbs path */}
        <nav className="hidden md:flex items-center gap-2 text-xs text-slate-400">
          {crumbs.map((crumb, idx) => (
            <div key={idx} className="flex items-center gap-1.5">
              {idx > 0 && <span className="text-[10px] text-slate-300">/</span>}
              {idx === crumbs.length - 1 ? (
                <span className="text-slate-700 font-semibold">{crumb.label}</span>
              ) : (
                <Link href={crumb.href} className="hover:text-primary hover:underline transition-colors">
                  {crumb.label}
                </Link>
              )}
            </div>
          ))}
        </nav>
      </div>

      {/* User Name & Logout Dropdown */}
      <div className="flex items-center gap-1.5 cursor-pointer group relative py-3">
        <Link href="/goals?created=true" className="text-xs font-semibold text-slate-700 hover:text-primary transition-colors">
          {employee?.employee_name || employee?.name || 'User'}
        </Link>
        <span className="text-[9px] text-slate-400">▼</span>

        {/* Dropdown Menu */}
        <div className="absolute right-0 top-full mt-0 hidden group-hover:block z-50 bg-white border border-[#dee2e6] rounded shadow-md py-1 w-32">
          <Link
            href="/goals?created=true"
            className="block w-full text-left px-3 py-2 text-xs text-slate-700 hover:bg-slate-50 transition-colors font-medium"
          >
            Created Goals
          </Link>
          <button
            onClick={handleLogout}
            className="w-full text-left px-3 py-2 text-xs text-slate-700 hover:bg-slate-50 hover:text-red-600 border-t border-slate-100 transition-colors font-medium cursor-pointer"
          >
            Sign Out
          </button>
        </div>
      </div>
    </header>
  )
}

export function TopBar(props) {
  return (
    <Suspense fallback={<header className="h-14 bg-white border-b border-[#dee2e6]" />}>
      <TopBarContent {...props} />
    </Suspense>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { goalsApi } from '@/lib/api'
import { getEmployee } from '@/lib/auth'
import { toast } from 'sonner'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Textarea } from '@/components/ui/textarea'
import { Avatar, AvatarFallback } from '@/components/ui/avatar'
import { Skeleton } from '@/components/ui/skeleton'
import { MessageSquare, Send, Trash2, Loader2 } from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'

function getInitials(name = '') {
  return name.split(' ').slice(0, 2).map((n) => n[0]).join('').toUpperCase()
}

export function CommentThread({ goalNo, readOnly }) {
  const [comments, setComments] = useState([])
  const [loading, setLoading] = useState(true)
  const [message, setMessage] = useState('')
  const [submitting, setSubmitting] = useState(false)
  const [currentEmployee, setCurrentEmployee] = useState(null)

  useEffect(() => {
    setCurrentEmployee(getEmployee())
    fetchComments()
  }, [goalNo])

  const fetchComments = async () => {
    try {
      const res = await goalsApi.getComments(goalNo)
      setComments(res.data?.data?.comments || res.data?.comments || res.data?.data || (Array.isArray(res.data) ? res.data : []))
    } catch {}
    finally { setLoading(false) }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    if (!message.trim()) return

    setSubmitting(true)
    try {
      await goalsApi.addComment(goalNo, message.trim())
      setMessage('')
      toast.success('Comment added')
      fetchComments()
    } catch (err) {
      toast.error(err?.response?.data?.message || 'Failed to add comment')
    } finally {
      setSubmitting(false)
    }
  }

  const handleDelete = async (commentNo) => {
    try {
      await goalsApi.deleteComment(goalNo, commentNo)
      setComments((c) => c.filter((cm) => cm.comment_no !== commentNo))
      toast.success('Comment deleted')
    } catch {
      toast.error('Failed to delete comment')
    }
  }

  return (
    <Card className="border border-slate-200 border-t-[3px] border-t-primary shadow-sm rounded-none bg-white font-sans">
      <CardHeader className="pb-3 border-b border-slate-100">
        <CardTitle className="text-base font-semibold flex items-center gap-2 text-slate-800">
          <MessageSquare className="h-4 w-4 text-primary" />
          Comments
          {!loading && (
            <span className="text-xs font-normal text-slate-400">({comments.length})</span>
          )}
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4 pt-4">
        {/* Comment list */}
        {loading ? (
          <div className="space-y-4">
            {[...Array(2)].map((_, i) => (
              <div key={i} className="flex gap-3">
                <Skeleton className="h-8 w-8 rounded-full shrink-0" />
                <div className="flex-1 space-y-1.5">
                  <Skeleton className="h-3.5 w-32" />
                  <Skeleton className="h-10 w-full rounded" />
                </div>
              </div>
            ))}
          </div>
        ) : comments.length === 0 ? (
          <p className="text-xs text-slate-400 text-center py-4">No comments yet. Be the first to comment!</p>
        ) : (
          <div className="space-y-4">
            {comments.map((c) => {
              const isOwn = !readOnly && (c.author || c.employee)?.employee_no === currentEmployee?.employee_no
              return (
                <div key={c.comment_no} className="flex gap-3 group">
                  <Avatar className="h-8 w-8 shrink-0 bg-slate-100 border border-slate-200">
                    <AvatarFallback className="bg-slate-100 text-slate-700 text-xs font-semibold">
                      {getInitials((c.author || c.employee)?.employee_name || (c.author || c.employee)?.name)}
                    </AvatarFallback>
                  </Avatar>
                  <div className="flex-1 min-w-0">
                    <div className="flex items-baseline gap-2 mb-1">
                      <span className="text-xs font-semibold text-slate-800">{(c.author || c.employee)?.employee_name || (c.author || c.employee)?.name || 'Unknown'}</span>
                      <span className="text-[10px] text-slate-400">
                        {c.created_at
                          ? formatDistanceToNow(new Date(c.created_at), { addSuffix: true })
                          : ''}
                      </span>
                    </div>
                    <div className="rounded bg-slate-50 border border-slate-100 px-3 py-2">
                      <p className="text-xs text-slate-700 leading-relaxed whitespace-pre-wrap">{c.message}</p>
                    </div>
                  </div>
                  {isOwn && (
                    <button
                      onClick={() => handleDelete(c.comment_no)}
                      className="opacity-0 group-hover:opacity-100 transition-opacity p-1.5 rounded-md text-slate-300 hover:text-red-500 hover:bg-red-50 self-start mt-1 cursor-pointer"
                    >
                      <Trash2 className="h-3.5 w-3.5" />
                    </button>
                  )}
                </div>
              )
            })}
          </div>
        )}

        {/* Add comment form */}
        {!readOnly && (
          <form onSubmit={handleSubmit} className="flex gap-3 items-end border-t border-slate-100 pt-4">
            <Avatar className="h-8 w-8 shrink-0 bg-slate-100 border border-slate-200 self-start mt-0.5">
              <AvatarFallback className="bg-slate-100 text-slate-700 text-xs font-semibold">
                {getInitials((currentEmployee?.employee_name || currentEmployee?.name))}
              </AvatarFallback>
            </Avatar>
            <div className="flex-1 space-y-2">
              <Textarea
                placeholder="Write a comment…"
                value={message}
                onChange={(e) => setMessage(e.target.value)}
                rows={2}
                className="resize-none text-xs rounded-none"
                onKeyDown={(e) => {
                  if (e.key === 'Enter' && e.metaKey) handleSubmit(e)
                }}
              />
              <div className="flex justify-end">
                <Button
                  type="submit"
                  size="sm"
                  className="bg-primary hover:bg-primary/95 text-white font-semibold rounded-none cursor-pointer text-xs h-8"
                  disabled={submitting || !message.trim()}
                >
                  {submitting
                    ? <Loader2 className="h-3.5 w-3.5 animate-spin" />
                    : <><Send className="h-3 w-3 mr-1.5" /> Send</>
                  }
                </Button>
              </div>
            </div>
          </form>
        )}
      </CardContent>
    </Card>
  )
}

